def decide(reg: dict) -> str:
    for art in reg.values():
        if not art.get("owner"):
            return "ESCALATE_NO_OWNER"
        if art.get("breaking") and art.get("bump") != "major":
            return "REJECT_BUMP_POLICY"
    return "CONTINUE"

