def decide(packet: dict):
    has_ev = bool(packet.get("evidence"))
    has_gp = bool(packet.get("graph_path"))
    if not has_ev and not has_gp:
        return "REJECT_SCORE_ALONE", 0
    if "uncertainty" not in packet:
        return "REQUEST_UNCERTAINTY", 0
    if has_ev and has_gp:
        return "CONTINUE", 4
    return "REJECT_PACKET_INCOMPLETE", 0

