def decide(paths: list):
    need = {"happy", "override", "ood_abstain"}
    got = set(paths)
    if got == {"happy"}:
        return "REJECT_HAPPY_ONLY", len(paths)
    if not need.issubset(got):
        return "REQUEST_DEMO_PATH", len(paths)
    return "CONTINUE", len(paths)

print(*decide(["happy", "override", "ood_abstain"]))

